// Define the Node class
class Node {
  constructor(value) {
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

// Define the function to traverse the tree
function traverse(node) {
  if (node === null) {
    return;
  }
  traverse(node.left);
  process.stdout.write(node.value + ' ');
  traverse(node.right);
}

// Create a binary tree with values 4, 2, 5, 1, 3
var root = new Node(4);
root.left = new Node(2);
root.right = new Node(5);
root.left.left = new Node(1);
root.left.right = new Node(3);
traverse(root);
